sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {
    var gr = new GlideRecord(current.getTableName());

    // Ensure 'requester' is the actual database column name
    var reqID = current.getValue('requester');
    gr.addQuery('requester', reqID);
    gr.addQuery('sys_id', '!=', current.getUniqueValue());
    gr.orderByDesc('sys_created_on');
    gr.setLimit(5);
    gr.query();

    if (gr.hasNext()) {
        template.print('<table style="width:100%; border:1px solid #ddd; border-collapse:collapse; font-family:sans-serif;">');
        template.print('<tr style="background-color:#f8f9fa;"><th style="padding:8px; border:1px solid #ddd; text-align:left;">Number</th><th style="padding:8px; border:1px solid #ddd; text-align:left;">Short Description</th></tr>');

        while (gr.next()) {
            template.print('<tr>');
            template.print('<td style="padding:8px; border:1px solid #ddd;">' + gr.getValue('number') + '</td>');
            template.print('<td style="padding:8px; border:1px solid #ddd;">' + gr.getValue('short_description') + '</td>');
            template.print('</tr>');
        }
        template.print('</table>');
    } else {
        // This helps you verify the script is actually running but found nothing
        template.print('<p>No previous requests found for this user.</p>');
    }
})(current, template, email, email_action, event);
